 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import {
 6	  Checkbox,
 7	  Flex,
 8	  FlexItem,
 9	  InputGroup,
10	  InputGroupItem,
11	  InputGroupText,
12	  Popover,
13	  StackItem,
14	  TextInput,
15	} from '@patternfly/react-core';
16	import { HelpIcon } from '@patternfly/react-icons';
17	
18	import './grace-period-input.scss';
19	
20	interface GracePeriodInputProps {
21	  gracePeriodSeconds: null | number;
22	  isChecked: boolean;
23	  onCheckboxChange: (checked: boolean) => void;
24	  setGracePeriodSeconds: (newGracePeriod: null | number) => void;
25	}
26	
27	export const GracePeriodInput: FC<GracePeriodInputProps> = ({
28	  gracePeriodSeconds,
29	  isChecked,
30	  onCheckboxChange,
31	  setGracePeriodSeconds,
32	}) => {
33	  const { t } = useKubevirtTranslation();
34	
35	  return (
36	    <StackItem>
37	      <Flex
38	        alignItems={{ default: 'alignItemsCenter' }}
39	        className="grace-period-input"
40	        spaceItems={{ default: 'spaceItemsXs' }}
41	      >
42	        <FlexItem>
43	          <Checkbox
44	            id="grace-period-checkbox"
45	            isChecked={isChecked}
46	            label={t('With grace period')}
47	            onChange={(_, checked) => onCheckboxChange(checked)}
48	          />
49	        </FlexItem>
50	        <FlexItem>
51	          <Popover
52	            bodyContent={
53	              <div>
54	                {t(
55	                  'The duration in seconds before the object should be deleted. Value must be non-negative integer. The value zero indicates delete immediately. If this value is nil, the default grace period for the specified type will be used. Defaults to a per object value if not specified. zero means delete immediately.',
56	                )}
57	              </div>
58	            }
59	          >
60	            <HelpIcon />
61	          </Popover>
62	        </FlexItem>
63	
64	        {isChecked && (
65	          <FlexItem>
66	            <InputGroup>
67	              <InputGroupItem isFill>
68	                <TextInput
69	                  onChange={(_event, value) =>
70	                    setGracePeriodSeconds(isEmpty(value) ? null : parseInt(value))
71	                  }
72	                  aria-label={t('seconds')}
73	                  data-test="grace-period-seconds-input"
74	                  min={0}
75	                  type="number"
76	                  value={gracePeriodSeconds}
77	                />
78	              </InputGroupItem>
79	              <InputGroupText>{t('seconds')}</InputGroupText>
80	            </InputGroup>
81	          </FlexItem>
82	        )}
83	      </Flex>
84	    </StackItem>
85	  );
86	};

